import sys
from typing import Optional

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def findTarget(self, root: TreeNode, target: int) -> bool:
        self.nodes = set()
        return self.dfs(root, target)

    def dfs(self, node: TreeNode, target: int) -> bool:
        if not node:
            return False
        complement = target - node.val
        if complement in self.nodes:
            return True
        self.nodes.add(node.val)
        return self.dfs(node.left, target) or self.dfs(node.right, target)

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        nodes = [int(next(it)) for _ in range(n)]
        target = int(next(it))
    except StopIteration:
        sys.exit(0)
