#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    bool findTarget(TreeNode* root, int target) {
        unordered_set<int> nodes;
        return dfs(root, target, nodes);
    }

private:
    bool dfs(TreeNode* node, int target, unordered_set<int>& nodes) {
        if (!node) return false;
        int complement = target - node->val;
        if (nodes.find(complement) != nodes.end()) return true;
        nodes.insert(node->val);
        return dfs(node->left, target, nodes) || dfs(node->right, target, nodes);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nodes(n);
    for (int i = 0; i < n; i++) cin >> nodes[i];
    int target;
    if (!(cin >> target)) return 0;
    TreeNode* root = nullptr;
    for (int node_val : nodes) {
        if (!root) {
            root = new TreeNode(node_val);
        } else {
            TreeNode* current = root;
            while (true) {
                if (node_val < current->val) {
                    if (!current->left) {
                        current->left = new TreeNode(node_val);
                        break;
                    }
                    current = current->left;
                } else {
                    if (!current->right) {
                        current->right = new TreeNode(node_val);
                        break;
                    }
                    current = current->right;
                }
            }
        }
    }
    Solution sol;
    bool ans = sol.findTarget(root, target);
    cout << (ans ? "YES" : "NO") << "\n";
    return 0;
}
